-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW iceberg.brain_serving.mv_metric_cac_new_all AS
WITH base AS (
  SELECT
    brand_id,
    currency_code,
    platform,
    SUM(spend_minor) AS spend_minor,
    SUM(new_customer_orders_attributed) AS new_customer_orders
  FROM iceberg.brain_serving.semantic_campaign
  WHERE ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3
)
SELECT
  brand_id,
  currency_code,
  platform,
  spend_minor,
  new_customer_orders,
  (spend_minor / NULLIF(new_customer_orders, 0)) AS cac_new
FROM base;
